import{_ as d,o as r,c as a,ag as e}from"./chunks/framework.DXGyWiRo.js";const i="/media/202309//1693899373.0902379.png",o="/media/202309//1693899373.0975025.png",g=JSON.parse('{"title":"RK3328 评估板白皮书","description":"","frontmatter":{"title":"RK3328 评估板白皮书"},"headers":[],"relativePath":"hardware/rk3328-evb/whitepaper.md","filePath":"hardware/rk3328-evb/whitepaper.md","lastUpdated":null}'),l={name:"hardware/rk3328-evb/whitepaper.md"};function n(h,t,p,s,c,b){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="目-录" tabindex="-1">目 录 <a class="header-anchor" href="#目-录" aria-label="Permalink to &quot;目 录&quot;">​</a></h1><ol><li>产品概述</li><li>产品实物图</li><li>硬件接口说明</li><li>功能描述 4.1. 产品特性 4.2. 硬件规格参数 4.3. 系统软件</li><li>适用场景</li><li>订货信息</li></ol><h1 id="离线资料下载" tabindex="-1">离线资料下载 <a class="header-anchor" href="#离线资料下载" aria-label="Permalink to &quot;离线资料下载&quot;">​</a></h1><p>RK3328评估板开发资料（产品白皮书、规格书、使用手册），可以点击下载: <a href="/media/attachment/2026/01/RK3328%E8%AF%84%E4%BC%B0%E6%9D%BF%E4%BA%A7%E5%93%81%E8%B5%84%E6%96%99.zip">【附件】RK3328评估板产品资料.zip</a></p><h1 id="产品概述" tabindex="-1">产品概述 <a class="header-anchor" href="#产品概述" aria-label="Permalink to &quot;产品概述&quot;">​</a></h1><p>RK3328评估板套件是一站式语音交互解决方案，该套件包含RK3328 系统板 + 麦克风阵列板（线性四麦+线性六麦+环形六麦）。支持唤醒打断、全双工交互、UART 串口与上位机通信。可广泛应用在智能服务机器人、智能家居中控、自助服务终端等智能设备产品。</p><h1 id="产品实物图" tabindex="-1">产品实物图 <a class="header-anchor" href="#产品实物图" aria-label="Permalink to &quot;产品实物图&quot;">​</a></h1><p><img src="'+i+'" alt="C:sersjyu2esktop线材料待审核K3328 AIUI评估板开发套件上线材料icture估板全家福.png评估板全家福" title="null"></p><h1 id="硬件接口" tabindex="-1">硬件接口 <a class="header-anchor" href="#硬件接口" aria-label="Permalink to &quot;硬件接口&quot;">​</a></h1><p><img src="'+o+'" alt="" title="null"></p><p>图 2 RK3328 评估板接口</p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>编号</strong></td><td><strong>接口名称</strong></td><td><strong>说明</strong></td></tr><tr><td>1</td><td>网口</td><td>连接网线，百M网口</td></tr><tr><td>2</td><td>HDMI</td><td>连接电视输出</td></tr><tr><td>3</td><td>复位按键</td><td>刷机按键</td></tr><tr><td>4</td><td>USB接口</td><td>USB Host口</td></tr><tr><td>5</td><td>USB接口</td><td>USB OTG口（刷机时需外接电源）</td></tr><tr><td>6</td><td>电源</td><td>DC12V 2A， DC5.5-2.1</td></tr><tr><td>7</td><td>电源座子</td><td>电源插头 PH2.54-2pin</td></tr><tr><td>8</td><td>喇叭</td><td>10W 4Ω 扬声器接口， PH2.54 4pin</td></tr><tr><td>9</td><td>耳机口</td><td>左右声道立体声输出</td></tr><tr><td>10</td><td>I2S</td><td>GPIO口复用I2S</td></tr><tr><td>11</td><td>MIC口</td><td>4/6 麦麦克风阵列接口</td></tr><tr><td>12</td><td>红外</td><td>红外控制</td></tr><tr><td>13</td><td>I2C</td><td>驱动灯板</td></tr><tr><td>14</td><td>UART1</td><td>协议串口TTL3.3V 波特率：由应用指定，H2.0-4P</td></tr><tr><td>15</td><td>UART2</td><td>调试串口TTL3.3V 波特率：1500000， PH2.0-4P</td></tr></tbody></table><h1 id="功能描述" tabindex="-1">功能描述 <a class="header-anchor" href="#功能描述" aria-label="Permalink to &quot;功能描述&quot;">​</a></h1><h2 id="产品特性" tabindex="-1">产品特性 <a class="header-anchor" href="#产品特性" aria-label="Permalink to &quot;产品特性&quot;">​</a></h2><p><strong>远场拾音</strong></p><p>运用远场降噪技术，可以使得拾音距离达到 5 米。</p><p><strong>180°（线性4麦和线性6麦）和360°（环形6麦）声源定位</strong></p><p>利用麦克风阵列技术，实现 180°（线性4麦和线性6麦）和360°（环形6麦）的语音信号采集，并通过声源定位来确定说话人的方向。精度可达±10°。</p><p><strong>回声消除</strong></p><p>在播放和录音同时进行的交互场景，模块通过回声消除技术，可以将扬声器的声音屏蔽，只接收用户的声音。</p><p><strong>定向拾音</strong></p><p>根据麦克风阵列的波束形成技术，可进行指定方向拾音。对波束外声音进行抑制，波束内声音进行增强，从而提升远程拾音效果。</p><p><strong>功放输出</strong></p><p>模块自带双路 5W 功放芯片。用户可直接接入喇叭进行语音交互。</p><p><strong>语音唤醒</strong></p><p>用户通过指定唤醒词的语音信号可以唤醒模块，也可设置模块开机自动唤醒。模块唤醒会上报唤醒信息，该信息包括唤醒角度、唤醒得分、所属波束、唤醒词等。</p><p><strong>语音交互体验</strong></p><p>不同角度唤醒，持续语音交互，支持AIUI在线语音识别，语义理解，语音合成等能力体验。</p><p><strong>定制开发</strong></p><p>支持 AIUI 语音 SDK 二次开发，支持 UART 串口通信二次开发</p><h2 id="硬件规格参数" tabindex="-1">硬件规格参数 <a class="header-anchor" href="#硬件规格参数" aria-label="Permalink to &quot;硬件规格参数&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>硬件主要参数</strong></td><td></td></tr><tr><td>主控芯片</td><td>Rockchip RK3328</td></tr><tr><td>处理器</td><td>4 核 ARM® Cortex-A53 64位处理器，主频 1.5GHz</td></tr><tr><td>图形处理器</td><td>ARM Mali-450 MP2 四核 GPU；支持 OpenGL ES1.1/2.0, OpenVG1.1</td></tr><tr><td>内存</td><td>DDR3 2GB（1GB/4GB 可定制）</td></tr><tr><td>存储器</td><td>高速 eMMC5.1 8GB （16GB/32GB/64GB/128GB 可定制）</td></tr><tr><td>以太网</td><td>10/100Mbps 以太网接口</td></tr><tr><td>WiFi</td><td>2.4G/5G 802.11a/b/g/n/ac 2T2R 2.4G/5G 802.11a/b/g/n/ac 蓝牙支持 Bluetooth 4.2</td></tr><tr><td>显示</td><td>1 x HDMI 2.0, 支持 4K@60Hz 显示输出，支持 HDCP1.4/2.2</td></tr><tr><td>音频</td><td>1 x HDMI 音频输出、 1×耳机音频输出</td></tr><tr><td>扩展接口</td><td>支持 GPIO（I²S、I²C、ADC）</td></tr><tr><td>USB</td><td>USB 2.0 Host × 1、USB_OTG × 1</td></tr><tr><td>红外</td><td>1 路红外接收头，支持红外遥控功能</td></tr><tr><td>串口</td><td>协议串口*1 debug串口*1</td></tr><tr><td>电源</td><td>12V 2A</td></tr></tbody></table><h2 id="系统软件" tabindex="-1">系统软件 <a class="header-anchor" href="#系统软件" aria-label="Permalink to &quot;系统软件&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>系统软件</strong></td><td></td></tr><tr><td>系统</td><td>Android/Linux，默认是 Android7.1</td></tr></tbody></table><p>表 3 RK3328 AIUI评估板开发套件系统软件表</p><h1 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h1><ul><li>教培行业，偏向于大专院校</li><li>远程会议、庭审等</li><li>家庭智能服务机器人</li><li>地铁自助服务终端</li><li>智能家居中控</li><li>大屏语音调度</li></ul><h1 id="订货信息" tabindex="-1">订货信息 <a class="header-anchor" href="#订货信息" aria-label="Permalink to &quot;订货信息&quot;">​</a></h1><p>请联系商务mail to：<a href="mailto:aiui_support@iflytek.com" target="_blank" rel="noreferrer">aiui_support@iflytek.com</a></p>',39)])])}const m=d(l,[["render",n]]);export{g as __pageData,m as default};
